def serve(host: str = "0.0.0.0", port: int = 50051, max_workers: int = 10,
          enable_reflection: bool = True):
    """
    Start the gRPC External Authorization server.

    Args:
        host: Host to bind to
        port: Port to listen on
        max_workers: Maximum number of thread pool workers
        enable_reflection: Enable gRPC reflection for debugging
    """
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        options=[
            ("grpc.max_send_message_length", 10 * 1024 * 1024),
            ("grpc.max_receive_message_length", 10 * 1024 * 1024),
            ("grpc.keepalive_time_ms", 30000),
            ("grpc.keepalive_timeout_ms", 10000),
            ("grpc.keepalive_permit_without_calls", True),
            ("grpc.http2.max_pings_without_data", 0),
            ("grpc.http2.min_time_between_pings_ms", 10000),
        ],
    )

    # Create and register the auth service
    policy = AuthorizationPolicy()
    auth_service = EnvoyExternalAuthService(policy=policy)
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(auth_service, server)

    # Enable gRPC reflection (useful for grpcurl debugging)
    if enable_reflection:
        try:
            from grpc_reflection.v1alpha import reflection
            SERVICE_NAMES = (
                external_auth_pb2.DESCRIPTOR.services_by_name["Authorization"].full_name,
                reflection.SERVICE_NAME,
            )
            reflection.enable_server_reflection(SERVICE_NAMES, server)
            logger.info("gRPC reflection enabled")
        except ImportError:
            logger.warning("grpc-reflection not installed, reflection disabled")

    listen_addr = f"{host}:{port}"
    server.add_insecure_port(listen_addr)
    server.start()

    logger.info(f"Envoy External Authorization gRPC server started on {listen_addr}")
    logger.info(f"Max workers: {max_workers}")
    logger.info("Configured policies:")
    logger.info(f"  - API keys: {len(policy.api_keys)}")
    logger.info(f"  - JWT tokens: {len(policy.jwt_tokens)}")
    logger.info(f"  - Path policies: {len(policy.path_policies)}")
    logger.info(f"  - Blocked IPs: {len(policy.blocked_ips)}")

    print(f"""
╔══════════════════════════════════════════════════════╗
║  Envoy External Authorization Service               ║
║  Listening on: {listen_addr:<38s} ║
║                                                      ║
║  Envoy config snippet:                               ║
║  http_filters:                                       ║
║    - name: envoy.filters.http.ext_authz              ║
║      typed_config:                                   ║
║        "@type": ...ext_authz.v3.ExtAuthz             ║
║        grpc_service:                                 ║
║          envoy_grpc:                                 ║
║            cluster_name: ext-authz                   ║
║          timeout: 0.5s                               ║
╚══════════════════════════════════════════════════════╝
    """)

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down...")
        server.stop(grace=5)
        logger.info("Server stopped")


def serve_with_tls(host: str = "0.0.0.0", port: int = 50051,
                   cert_file: str = "server.crt",
                   key_file: str = "server.key",
                   ca_file: Optional[str] = None,
                   max_workers: int = 10):
    """
    Start the gRPC External Authorization server with TLS.

    Args:
        host: Host to bind to
        port: Port to listen on
        cert_file: Path to server certificate
        key_file: Path to server private key
        ca_file: Path to CA certificate for client verification (mTLS)
        max_workers: Maximum number of thread pool workers
    """
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=max_workers))

    policy = AuthorizationPolicy()
    auth_service = EnvoyExternalAuthService(policy=policy)
    external_auth_pb2_grpc.add_AuthorizationServicer_to_server(auth_service, server)

    # Load TLS credentials
    with open(key_file, "rb") as f:
        private_key = f.read()
    with open(cert_file, "rb") as f:
        certificate_chain = f.read()

    root_certificates = None
    if ca_file:
        with open(ca_file, "rb") as f:
            root_certificates = f.read()

    credentials = grpc.ssl_server_credentials(
        [(private_key, certificate_chain)],
        root_certificates=root_certificates,
        require_client_auth=ca_file is not None,
    )

    listen_addr = f"{host}:{port}"
    server.add_secure_port(listen_addr, credentials)
    server.start()

    logger.info(f"Envoy External Authorization gRPC server started on {listen_addr} (TLS)")
    if ca_file:
        logger.info("mTLS enabled - client certificate required")

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down...")
        server.stop(grace=5)


